        m.insert("quoteVolume".to_string(), quoteVolume.clone());
        m.insert("markPrice".to_string(), self.safe_string_k(ticker.clone(), "markPrice", &[]));
        m.insert("indexPrice".to_string(), self.safe_string_k(ticker.clone(), "indexPrice", &[]));
